-- Resolve location FKs from crawled admin names / nearest city when possible.
UPDATE gym_directory d
SET state_id = s.id,
    state_name = COALESCE(d.state_name, s.name->>'ko')
FROM location_states s
WHERE d.state_id IS NULL
  AND s.country_code = 'KR'
  AND d.state_name IS NOT NULL
  AND (
    d.state_name ILIKE '%' || (s.name->>'ko') || '%'
    OR d.state_name ILIKE '%' || (s.name->>'en') || '%'
    OR (s.name->>'ko') ILIKE '%' || d.state_name || '%'
  );

UPDATE gym_directory d
SET city_id = c.id,
    city_name = COALESCE(d.city_name, c.name->>'ko'),
    state_id = COALESCE(d.state_id, c.state_id)
FROM location_cities c
WHERE d.city_id IS NULL
  AND d.city_name IS NOT NULL
  AND (
    d.city_name ILIKE '%' || (c.name->>'ko') || '%'
    OR (c.name->>'ko') ILIKE '%' || d.city_name || '%'
  );

UPDATE gym_directory d
SET district_id = x.id,
    district_name = COALESCE(d.district_name, x.name->>'ko'),
    city_id = COALESCE(d.city_id, x.city_id)
FROM location_districts x
WHERE d.district_id IS NULL
  AND d.district_name IS NOT NULL
  AND (
    d.district_name ILIKE '%' || (x.name->>'ko') || '%'
    OR (x.name->>'ko') ILIKE '%' || d.district_name || '%'
  );

-- Fill missing city/state using nearest KR city by coordinates.
UPDATE gym_directory d
SET city_id = nearest.city_id,
    state_id = nearest.state_id,
    city_name = COALESCE(d.city_name, nearest.city_name),
    state_name = COALESCE(d.state_name, nearest.state_name)
FROM (
  SELECT DISTINCT ON (g.id)
    g.id AS gym_id,
    c.id AS city_id,
    c.state_id,
    c.name->>'ko' AS city_name,
    s.name->>'ko' AS state_name
  FROM gym_directory g
  JOIN location_cities c ON c.latitude IS NOT NULL AND c.longitude IS NOT NULL
  JOIN location_states s ON s.id = c.state_id AND s.country_code = 'KR'
  WHERE g.city_id IS NULL
    AND g.latitude IS NOT NULL
    AND g.longitude IS NOT NULL
  ORDER BY g.id,
    ((g.latitude - c.latitude) * (g.latitude - c.latitude)
      + (g.longitude - c.longitude) * (g.longitude - c.longitude)) ASC
) nearest
WHERE d.id = nearest.gym_id
  AND d.city_id IS NULL;
